// Case-insensitive substring search for byte vectors
static bool ci_contains(const std::vector<char>& haystack, const std::string& needle) {
    if (needle.empty()) return true;
    if (haystack.size() < needle.size()) return false;

    std::string upper_needle = needle;
    std::transform(upper_needle.begin(), upper_needle.end(), upper_needle.begin(), ::toupper);

    for (size_t i = 0; i <= haystack.size() - upper_needle.size(); ++i) {
        bool match = true;
        for (size_t j = 0; j < upper_needle.size(); ++j) {
            if (toupper(static_cast<unsigned char>(haystack[i + j])) != static_cast<unsigned char>(upper_needle[j])) {
                match = false;
                break;
            }
        }
        if (match) return true;
    }
    return false;
}

// Minimal secure XML parser
static XmlNode parse_xml(const std::vector<char>& raw) {
    std::string content(raw.begin(), raw.end());
    XmlNode root;
    bool root_set = false;
    size_t pos = 0;

    while (pos < content.size()) {
        size_t open = content.find('<', pos);
        if (open == std::string::npos) break;

        size_t close = content.find('>', open);
        if (close == std::string::npos) break;

        std::string tag_content = content.substr(open + 1, close - open - 1);
        pos = close + 1;

        if (tag_content.empty() || tag_content[0] == '?' || tag_content[0] == '!') {
            continue; // Skip processing instructions and comments
        }

        if (tag_content[0] == '/') {
            continue; // End tag
        }

        // Extract tag name (ignoring attributes)
        size_t space_pos = tag_content.find(' ');
        std::string tag_name = (space_pos != std::string::npos) ? tag_content.substr(0, space_pos) : tag_content;

        // Handle self-closing tags
        if (!tag_name.empty() && tag_name.back() == '/') {
            tag_name.pop_back();
            XmlNode node;
            node.tag = tag_name;
            if (root_set) {
                root.children.push_back(std::move(node));
            } else {
                root = std::move(node);
                root_set = true;
            }
            continue;
        }

        XmlNode node;
        node.tag = tag_name;

        // Extract text content until the next tag
        size_t next_open = content.find('<', pos);
        if (next_open != std::string::npos) {
            node.text = content.substr(pos, next_open - pos);
        }

        if (root_set) {
            root.children.push_back(std::move(node));
        } else {
            root = std::move(node);
            root_set = true;
        }
    }

    return root;
}

