	if err != nil {
		return nil, errors.New("OSError")
	}

	upper := strings.ToUpper(string(raw))
	if strings.Contains(upper, "<!DOCTYPE") || strings.Contains(upper, "<!ENTITY") {
		return nil, errors.New("ValueError")
	}

